  private handleFormSubmit(formData: any) {
    console.log('Rendered form submitted:', formData);
    // Handle form submission in your Angular app
  }

  private cleanup() {
    if (this.editor?.destroy) {
      this.editor.destroy();
    }
    if (this.renderer?.destroy) {
      this.renderer.destroy();
    }
  }
